def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 2:
            priority = ratio ** 4 + np.sqrt(ratio)
        elif 1 < ratio <= 2:
            priority = ratio ** 3 - np.log(ratio)
        elif ratio == 1:
            priority = 0
        else:
            log_ratio = np.log(ratio)
            if log_ratio < -2:
                priority = -10 * log_ratio + ratio ** 2
            elif -2 <= log_ratio < -0.5:
                priority = -3 * log_ratio + 0.7 * ratio
            else:
                priority = -log_ratio + 0.3 * ratio ** 1.5
        if capacity < item * 0.3:
            priority += 3
            for j in range(i):
                if bins[j] > capacity:
                    priority += 0.5
        elif capacity > item * 3:
            priority -= 2
            for j in range(i + 1, len(bins)):
                if bins[j] < capacity:
                    priority -= 0.3
        else:
            if abs(capacity - item) < 0.1 * item:
                priority -= 1.5
            else:
                priority += 0.2 * abs(capacity - item) / item
        if i % 2 == 0:
            priority *= 0.95
        else:
            priority *= 1.05
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        min_priority = np.min(finite_priorities)
        for i in range(len(priorities)):
            if not np.isfinite(priorities[i]):
                priorities[i] = min_priority + 15
    return priorities
